import unittest

class TestSolution(unittest.TestCase):
    def test_basic_window_3(self):
        self.assertEqual(stock_moving_average([10, 20, 30, 40, 50], 3), [20.0, 30.0, 40.0])

    def test_window_2(self):
        self.assertEqual(stock_moving_average([100, 200, 300], 2), [150.0, 250.0])

    def test_constant_prices(self):
        self.assertEqual(stock_moving_average([5, 5, 5, 5], 2), [5.0, 5.0, 5.0])

    def test_hidden_single_element(self):
        self.assertEqual(stock_moving_average([42], 1), [42.0])

    def test_hidden_window_equals_length(self):
        self.assertEqual(stock_moving_average([10, 20], 2), [15.0])

    def test_hidden_full_window(self):
        self.assertEqual(stock_moving_average([1, 2, 3, 4, 5], 5), [3.0])

    def test_hidden_window_1(self):
        self.assertEqual(stock_moving_average([10, 20, 30, 40, 50], 1), [10.0, 20.0, 30.0, 40.0, 50.0])

    def test_hidden_non_round_averages(self):
        self.assertEqual(stock_moving_average([3, 1, 4, 1, 5, 9], 3), [2.67, 2.0, 3.33, 5.0])

if __name__ == '__main__':
    unittest.main()
